INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LCONT_PROD','Being supportive. Bring ideas to the table. He is good logistical go to guy.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LSTOP_COMM','Stop of what someone else should be doing. Yes someone else should resolve the problem but bring the solutions of why and how to get buy-in. He did great with project roll out.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LCREATIVE','Hestiant because they will become his job. Makes sense but he has excellent ideas to ensure all are included in the solution. He did a great job with rollout of IT project. He is great in our personal organization to provide mentorship to the youth.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LSTART_IMPACT','Become more technology savvy with social media and chat rooms. More structured time to review materials instead of waiting for the hallway update. Be present.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LSTOP_IMPACT','Nothing');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LCONT_IMPACT','Being a good collegue, friend, supportive of organization programmatic needs.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('6f8cca50-0f0c-40ea-bcb5-e3524a41f8d1','9bac645b-6633-41ad-8d85-4189c434df83','LDESCRIBE','Realiable. Good Decision making. Understands the assignment. Helps where needed.');
