INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LRELAT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LSTART_TRUST','I am not certain. He is open, well prepared, asks the right questions, and has been ultimately supportive in our collaboration.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LSTOP_INIT','He is giving the team members opportunities to share their ideas or points of view and as such I don''t see what he should/could stop.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LCONT_PROD','He should absolutely continue his calm, steady presence and clear guidance to our project. His manner of conducting this project keeps meetings focused and helps the components move forward efficiently.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LSTOP_COMM','Nothing - he''s concise and open for questions if there is clarification needed. The need for clarification is on me not on him.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LCREATIVE','He is calm and knows what he is talking about. He has a very tolerant nature and open air about him when approached with suggestions or questions.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LSTART_IMPACT','Maybe working even more on bringing teams together, but he''s already doing a great job.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LSTOP_IMPACT','He is doing a lot and I don''t know what he could stop to still have the project move forward as smoothly as he does. I am glad he was able to hire a couple of contractors to assist - as I WAS worried that there was TOO much on his plate.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LCONT_IMPACT','He is awesome at delegating and sharing his knowledge but also a sense of calmness and humor when discussions around specific topics need to be had.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','7263e557-c7cf-49ef-aa42-a55f86ba8677','LDESCRIBE','He is calm, knowledgeable, and has an awesome dry sense of humor. His quiet nature makes him wonderful to collaborate with but even more so does his deep knowledge of what we are working on.');
INSERT INTO diagnostic_raters (id,diagnostic_id,name,email,relationship,is_self,completed_at,created_at) VALUES ('cae227ec-ff63-4f65-9226-699264135d07','323c816d-f716-489c-86fb-c0d324ffdf2c','Halley Wheeless','hwheeless@abhs.k12.nm.us','External Partner',false,'2025-04-26T00:00:00Z','2025-04-26T00:00:00Z');
