INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LEXPECT',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LCRISIS',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LINSPIRE',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LRELAT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LSTART_TRUST','Hard to know, since I do not work with him on a daily basis but from what I can tell, he follows through on what he says he will do and that is the foundaton of trust for me.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LSTOP_INIT','I cannot answer this one as I don''t work closely enough with him.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LCONT_PROD','Keeping deadline hard and fast so people will rise to the occasion.  The office he works in (PED) has a problem with deadlines, however Steve works hard maintain productive reaasonable requests and from my observations, follows through and meets the deadlines he says he will meet.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LSTOP_COMM','I believe allowing the the use of any AI scribing program stifles the willingness of people to speak their minds and so there is less effective feedback as many people do not want their reponses or commentary sent out across the state. In education, people are very careful about what is written in emails and said in video recordings.  Allowing AI bots to record everything is unsettling ,in my opinion, therefore inhibiting frank and open communication.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LCREATIVE','I appreciate the way that he collects feedback from his stakeholders in real time but then makes feedback open to other for a set time for those who have not been able to attend. Furthemore, the extra five days or so to revisit an open feedback session has allowed me to think more about the issue and return to the topic to add to my initial thoughts.  This method of collection is new to me and has been valuable.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LSTART_IMPACT','Present more at the superintendent meetings.  Lobby for time to answer questions during the Thursday calls becuase once accreditation is published he will be attacked by those who failed to heed and listen, through no fault of his own.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LSTOP_IMPACT','Don''t use TEAMS for virtual meetings ever and do not allow the use of AI virtual scribes.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LCONT_IMPACT','Circling back around to address issues - Steve is good at noting, remembering, and following through with concerns. Follow through is everything becuase it increases trust, gives a sense of accountability on the part of the leader, and lets all stakeholders know they are listened to and not forgotten.  Even if the answer is ''NO'' for an ask.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','cae227ec-ff63-4f65-9226-699264135d07','LDESCRIBE','Highly effective at working across divisions and with diverse teams; organized and thoughtful.  Can be trusted.');
INSERT INTO diagnostic_raters (id,diagnostic_id,name,email,relationship,is_self,completed_at,created_at) VALUES ('5d727cb2-01be-4bbc-855b-a0462af22fec','323c816d-f716-489c-86fb-c0d324ffdf2c','Amanda DeBell','Amanda.DeBell@ped.nm.gov','Board / Investor',false,'2025-04-26T00:00:00Z','2025-04-26T00:00:00Z');
