INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LEXPECT',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LCRISIS',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LINSPIRE',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LRELAT',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','D1',8);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LSTART_TRUST','This leader could build relationship that leads to trust for example spending time with people on his teams.  This is not to say that he does not have trusting relationships now just something to consider.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LSTOP_INIT','This leader could learn from being both microscopic and macroscopic at the same time or at least zooming in and zooming out for important decisions and conversations.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LCONT_PROD','This leader makes sure to take the time to reiterate team productivity at each meeting.  This is a great skill.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LSTOP_COMM','Again, taking the time to see the big picture and the little details when analyzing situations.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LCREATIVE','The building of team has been a valuable approach to his style.  Learning and adapting from others has also been a solid approach.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LSTART_IMPACT','This is going to be hard, but the one thing that will elevate impact is sitting back and being able to delegate this work with a team.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LSTOP_IMPACT','I see Steven get emotionally involved.  This will lead to burn out. He can be cerebral but a nice mix of the two will lead to longevity.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LCONT_IMPACT','Steven is a fantastic listener and responder.  Because he is a thinker, he can pivot very easily.  That ability to respond is vital.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','5d727cb2-01be-4bbc-855b-a0462af22fec','LDESCRIBE','Steven is committed, personable and nimble.');
INSERT INTO diagnostic_raters (id,diagnostic_id,name,email,relationship,is_self,completed_at,created_at) VALUES ('4e00fa90-3f6d-4a28-a46c-c6123ef60004','323c816d-f716-489c-86fb-c0d324ffdf2c','Sara Cordova','sara.cordova3@ped.nm.gov','Peer',false,'2025-04-26T00:00:00Z','2025-04-26T00:00:00Z');
