INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LSTRAT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LCOLLAB',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LACCT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LEXPECT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LCRISIS',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LINSPIRE',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LRELAT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LSTART_TRUST','Start using a consistent, searchable place for updates (e.g., Teams posts or a running update log) instead of email whenever possible—this would make information easier to locate later and reduce inbox overload.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LSTOP_INIT','Doing less deep ‘what-if’ planning for low-probability situations—and using a lighter-touch risk scan with the option to expand only if needed—would free up time and empower the team to move forward with more initiative.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LCONT_PROD','Continue being highly accessible and collaborative—quickly jumping on a Teams call to work through questions and refine stakeholder messaging—while keeping work organized with clear timelines and follow-through. It keeps projects moving and reduces rework.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LSTOP_COMM','Use email less as the primary channel for updates; a centralized Teams hub would improve clarity and reduce missed information.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LCREATIVE','The accreditation rubric is a standout—simple, clear, and actionable. The broader accreditation process it supports has created much more consistency and efficiency, and it’s easy to build on with small refinements.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LSTART_IMPACT','Start opening key discussions by clarifying what success looks like, what decision needs to be made, and the main tradeoffs, so everyone aligns quickly and execution moves faster.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LSTOP_IMPACT','Stop defaulting to long email threads and extensive contingency planning—centralizing updates and focusing on the most likely scenarios would make communication and execution more efficient.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LCONT_IMPACT','Continue the combination of accessibility and structure: responsive support, clear direction, and strong timeline management.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','4e00fa90-3f6d-4a28-a46c-c6123ef60004','LDESCRIBE','Calm, empathetic, and professional; highly collaborative and solution-oriented; approachable and supportive; organized and timeline-driven with strong follow-through—reliable, fair, and consistent.');
