INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','D1',9);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LSTART_TRUST','Steve is very thoughtful in his responses to query from team members.  He has been a key person in the state''s accreditation process development.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LSTOP_INIT','He may be concerned with offending those who he disagrees with.  He is very polite but may need to be more directive in his responses.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LCONT_PROD','pays attention to detail and considers cause and effect of decisions;  questions 7-9 are the same question??');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LSTOP_COMM','returning back to previous decisions prior to moving forward with new ones.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LCREATIVE','Steve is very methodical and sometimes doesn''t think outside the box.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LSTART_IMPACT','Promote himself and the decisions he is making.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LSTOP_IMPACT','Balance the work of the details with the overall picture.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LCONT_IMPACT','See section 15');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','234fd467-8637-47ec-b092-7660cde7a37b','LDESCRIBE','hard worker, smart, organized, thoughtful about impact of his decisions, good researcher and thinks about details');
