INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LSTART_TRUST','Continued growth in receiving feedback as an opportunity for refinement — rather than as critique — will enhance collaboration and leadership presence.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LSTOP_INIT','Stop attributing outcomes solely to external factors without self-reflection.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LCONT_PROD','Continue bringing strong commitment and conviction to their work');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LSTOP_COMM','Better understand that individual goals and aims related to the work at hand sometimes must be superseded to consider the broader work of the division or other work needs that are apart or that must reside alongside the individual work.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LCREATIVE','This leader is able to be deeply engaged with those projects and activities that serve his core work needs and work areas, which shows passion and commitment, but this leader must also understand sometimes personal work goals must be sacrificed for the broader good.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LSTART_IMPACT','The leader should develop a reflection journal of interactions held during the day to consider how he positively contributed to engagements and interactions.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LSTOP_IMPACT','The leader should be more self-reflective and consider what strategies he might develop for similar situations in the future, so as not (STOP) to come across blatant, aloof,  disengenuos, or being put off.  Assume "good intent" in every interaction.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LCONT_IMPACT','This leader shows strong commitment and passion for the projects assigned to him.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','791946d1-d118-4d07-9ff9-7495627d3461','LDESCRIBE','Steven is an intelligent program coordinator who demonstrates care and concern for projects and polices that he is passionate about.  He can be a great thought partner and has much to contribute.');
