INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LSTART_TRUST','Steve is consistent and dependable. He also knows his job well. I''m not sure what else he can do to build greater trust.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LSTOP_INIT','Perhaps he can reduce the number of projects he works on.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LCONT_PROD','Providing clear instruction and opportunities for help.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LSTOP_COMM','Steve has an effective communication style. No changes required.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LCREATIVE','The structure of the Department''s accreditation reporting framework.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LSTART_IMPACT','Focus on high-level priorities for the agency.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LSTOP_IMPACT','Steve has a tendency to take on a lot of work. I think it stems from a desire to help everyone. I think learning to say no sometimes would prove beneficial.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LCONT_IMPACT','Collaborating with others and maintaining a desire for constant improvement.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0257c17f-7552-4d48-a809-36761263a4c4','LDESCRIBE','Dependable, personable, collaborative, and intelligent.');
