INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LSTART_TRUST','Steven is assertive and has a great vision for projects. He builds strong relationships which is key to trust. I wouldn''t give him a suggestion as much as I would say to continue building relationships with peers.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LSTOP_INIT','Steven is very open to feedback. His vision is strong for projects. My only suggestion would be to wait for feedback from others prior to sharing thoughts.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LCONT_PROD','Building relationships and keeping the positive attitude which he has already shared.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LSTOP_COMM','I don''t think there is anything Steven should stop. He has a great system and has a project management approach which is very helpful in completing big projects.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LCREATIVE','Steven always has a very strong and tangible vision for peers. I find this very valuable as I tend to be in the abstract so working with Steven helps to define some of the broader ideas that I contribute.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LSTART_IMPACT','I think continuing to grow in current areas of strength.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LSTOP_IMPACT','The only thing that I can suggest is that there are a lot of projects and sometimes capacity can be limited.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LCONT_IMPACT','Building relationships and sharing a clear and tangible vision for projects.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','71be96ca-f9ce-4400-beca-1dee971a7c78','LDESCRIBE','Extremely bright, easy and enjoyable to work with, a real team player.');
