INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LCOLLAB',3);
