INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LCRISIS',3);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LINSPIRE',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LRELAT',3);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LSTART_TRUST','I do not work with the leader as closely as I used to, so my advice may no longer apply. That said, I think the leader may benefit from slowing down when explaining things to people, understanding others are at different levels, and using that as an opportunity to connect with colleagues and team members.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LSTOP_INIT','For 5, I really do not know whether he does this or not, so my rating reflects N/A. For this question, I wonder if he could be better with delegating; though this is also an area I am unsure about.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LCONT_PROD','7-9 are the same questions and my answers reflects N/A. For this question, I want to highlight that the leader is naturally charismatic. While he is humble most of the time, I can see how his confidence may appear as arrogance to others. I do not believe the leader is arrogant because I had the wonderful opportunity to work with him for so long, and he is passionate about his work; but I can see how he may come off differently to others who do not know him or know that he means well.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LSTOP_COMM','I was recently in a meeting where someone said that we would benefit from the leader explaining something in the leader''s way of explaining because he does well with that. I think there is room for improvement, though, as I have seen when he does not display his best self, perhaps because those he was explaining to were not following *at all,* making for a difficult or frustrating conversation. Still, I think that it is in those precise times that I *know* the leader can use his charm and humility to connect with those folks; instead of becoming seemingly frustrated, he can use that opportunity to build trust with those who do not understand.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LCREATIVE','This leader has thought about creative ways in which we can use or maximize existing systems to achieve a goal (rather than creating something new). This leader''s work with accreditation has been significant for the agency, and will continue to be significant. It was his initiative, drive, and passion that made it what it is today, despite the system facing certain hurdles at times.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LSTART_IMPACT','This leader may consider "reading the room" to see how people are doing, if they know the why, and seeing how he can help them get there. (He has done this; I have seen him do this. Maybe being more intentional about it for all meetings would help.)');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LSTOP_IMPACT','I am not sure I have an answer here outside of what I shared before. This leader may consider not "hurrying" through meetings or assignments.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LCONT_IMPACT','This leader may consider continuing to check in with people before or after meetings just to see how they''re doing. It goes a long way when he leader does this.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','d842b350-182e-4984-b7ea-ce987ce5aab6','LDESCRIBE','Wonderful, driven, caring, funny, very smart. If you want something done, and you want it done well, with maybe a few dad jokes here and there along the way, then Steve''s your person.');
INSERT INTO diagnostic_raters (id,diagnostic_id,name,email,relationship,is_self,completed_at,created_at) VALUES ('7b347886-8f7d-4009-b57e-2bdba5704d05','323c816d-f716-489c-86fb-c0d324ffdf2c','David Vincent','david.vincent@ped.nm.gov','Peer',false,'2025-04-26T00:00:00Z','2025-04-26T00:00:00Z');
