INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LSTART_TRUST','My "north star" for trust is the Ability, Benevolence, Integrity (ABI) model. Steve does a lot to highlight the ability of those he works with. Perhaps providing more opportunities for teammates to demonstrate benevolence and integrity could foster more trust within and across teams.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LSTOP_INIT','Stop for just a moment or two more before providing summaries, next steps, or guidance. There may be people waiting to speak up but who need a minute of uncomfortable silence as "permission space" to do so.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LCONT_PROD','Continue to encourage communication among team members.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LSTOP_COMM','"stops" are hard because it is more subtle than that - but I think more clearly defining roles and responsibilities of team members would be useful. So maybe stop assuming that these things are understood or well defined.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LCREATIVE','DAWGs is a creative an fun name and the sessions have been great. The diverse topics of conversation keep people from different sectors engaged.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LSTART_IMPACT','Blow his own horn a little more. Share more about his areas of expertise and the outcomes of his projects.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LSTOP_IMPACT','Stop being so good at everything so that this STOP questions become a little easier to answer. Maybe slow down a touch on to wait for emerging opinions, solutions, or concerns to surface.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LCONT_IMPACT','Building connections among team members.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','425a5a7a-1ab5-4ef8-9df1-f0eb25dec236','LDESCRIBE','Steven is a community builder with a vison for the future.');
