INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LRELAT',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','D1',8);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LSTART_TRUST','Increase his understanding of how the data is collected, managed, and communicated to the PED. This might lead to a greater understanding that districts are trying their best but there are SYSTEMIC issues that are sometimes outside of a district''s control at play as well as effort.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LSTOP_INIT','Mr. Heil works with diverse stakeholders within his level and a number of districts. While I understand that working with everyone gets tricky and may lead to increased misunderstandings, communication with a new process like accreditation is extremely important and receiving feedback from all stakeholders and not just hand-picked people is important. I appreciate now having the opportunity to provide feedback but there are likely other people around the state who have relevant feedback to their situations who have not yet been provided the opportunity. So the advice would be to stop holding proposed actions so tight to the vest.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LCONT_PROD','Mr. Heil should continue to respond to emails quickly and to reach out to relevant stakeholders in order to find solutions effectively.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LSTOP_COMM','While this may not always be the case, Mr. Heil can start with the assumption that districts are trying their best to meet all of the statutory requirements. Inevitably not all districts meet the standards at every point in time. So the focus should be on the obstacles that districts face in meeting the requirements.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LCREATIVE','I appreciate his willingness to hear feedback and work with stakeholders to develop reasonable criteria based on their contexts. He has been willing to acknowledge unintended consequences.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LSTART_IMPACT','See prior answers.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LSTOP_IMPACT','See prior answers.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LCONT_IMPACT','See prior answers.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('323c816d-f716-489c-86fb-c0d324ffdf2c','0ef8392f-d28b-4148-8244-d6d82f325941','LDESCRIBE','Still learning how various systems work but willing to learn.');
