INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LSTART_TRUST','The one thing that I could start doing to build an even greater trust with colleagues and team members is to create a better communication environment.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LSTOP_INIT','The one thing I could STOP doing that might be hindering my team''s ability to take the initiative is providing too much direction.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LCONT_PROD','The one thing I should absolutely CONTINUE doing because it has a significant positive impact on team productivity is encouraging family first.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LSTOP_COMM','The one thing that I could stop doing to improve my communication or leadership effectiveness is allowing my personal opinions to cloud my judgement and communication.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LCREATIVE','The one creative approach that I have introduced that has been particularly valuable is an open door policy that we are always available and get a piece of chocolate.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LSTART_IMPACT','The one thing that I should START doing to elevate my leadership impact is to speak up more.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LSTOP_IMPACT','The one thing I should STOP doing to become more effective is to have a a negative mindset about certain situations.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LCONT_IMPACT','The one thing that I do exceptionally well that I should absolutely CONTINUE doing is to foster collaboration.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','5380640e-7f0a-459b-837c-700b01aa2da1','LDESCRIBE','If I were to describe myself to someone outside of the team, I would say that this person is connected, understanding, relevant and mindful.');
