INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LINSPIRE',3);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LRELAT',3);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','D1',9);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LSTART_TRUST','The leader could start more openly embracing and championing change, particularly when it comes from new offices or developing business lines. Their responsiveness and thoughtful consideration of broader impacts are significant strengths, but greater openness and transparency with peers, such as Vice Presidents and Project Managers, would help build deeper trust across the organization.
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LSTOP_INIT','One thing this leader could stop doing to help their team take greater initiative is escalating or discussing sensitive issues outside of the immediate team or peer relationship before the team has had a chance to fully understand the positions of both parties and to the company as a whole. 
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LCONT_PROD','This leader should absolutely continue streamlining existing processes and leveraging tools within their controls, such as Paycom, to reduce touch points and improve the efficiency of routine tasks that ensure the compliance that is crucial to the leaders own divisional interests. 
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LSTOP_COMM','One thing this leader could stop doing to improve their communication and leadership effectiveness is engaging outside of the established team or peer structure before fully understanding the context of an emerging initiative. While their intent is often to move discussions forward efficiently, bypassing the natural communication ladder or offering early opinions without an open dialogue with the peer championing the idea can unintentionally discourage junior team members and derail initiatives in their early stages.
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LCREATIVE','This leader has always had the solution I needed when the chips were down and a report or fellow employee needed support or assistance. Without going into all the specifics this leader knows how to navigate the system while maintaining compliance and getting to the desired outcome. Their readiness to tackle these challenges and develop creative solutions is noted.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LSTART_IMPACT','Embracing the changing landscape of the firm and join with others to be a champion of change. Heather''s role is absolutely mission critical to the success of any change as she ensures that the change or process is compliant with regulation and requirements. It is important though to fully and with an open mind evaluate change and requests to understand the why and to look for ways to mitigate the underlying problem. It is critical that a leader like Heather, with more internal procedural knowledge than anyone else at the firm, be attentive to the struggles and pain points of new leaders throughout the firm to understand how the process may need to adapt to enable continued growth.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LSTOP_IMPACT','Avoid informal workshopping or premature elevation of issues that erode trust with other parties. By virtue of her position Heather is more in-tune and in reach to ownership and senior management than any other VP. This makes it even more critical to be judicious in her approach and engagement to be a peer that other leaders can rely on and use as a sounding board. Internalizing these discussions and going to senior leadership or others in a collaborative manner would improve trust, communication, and integration.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LCONT_IMPACT','Looking out for the best interests of the firm and each and every employee including helping to find solutions to tricky problems that have real impacts to employees and their families. Heather is masterful at this!');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','94deaf2e-d177-428d-8cab-d3b602d30e44','LDESCRIBE','Competent, Caring, Traditional, Process Oriented');
