INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','d925964b-7b20-4687-b581-ee4ee7690866','LSTOP_INIT','Heather definitely takes initiative it''s just that the nature of HR is constant change in policy');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','d925964b-7b20-4687-b581-ee4ee7690866','LCONT_PROD','Heather''s finds solutions that are grey in a black and white field- and that''s great');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','d925964b-7b20-4687-b581-ee4ee7690866','LSTOP_COMM','Recognize engineers are horrible communicators');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','d925964b-7b20-4687-b581-ee4ee7690866','LCREATIVE','Hard to tell as Matt is much more vocal ... too vocal on HR stuff');
