INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','D1',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LSTART_TRUST','As an outside 3rd party I am unsure how to answer. In my experience, Heather understands how to make a business case for change. Doing so requires a level of transparency with leadership, gaining trust with factual detail - financials, etc. and engaging her team to execute. In my relationship with Heather, I watched her achieve all these things while elevating the role and skills in a more junior HR team member. Once less seasoned team members grasped concepts and showed proficiency, Heather fostered their growth with increasing responsibiity and independence. From the outside, her team trusted her and respected her, which included leadership.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LSTOP_INIT','I cannot speak to internal hinderances.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LCONT_PROD','Remaining a mentor leader and entrusting team members to execute more responsibility');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LSTOP_COMM','As an external partner, Heather''s goals and objectives for the organization were always clearly communicated. She navigates shifting priorities well also, which can be challenging for effective leadership.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LCREATIVE','From an external perspective, Heather seemed to be a concensus builder within my capacity working with her. My experience was with her and the WMA benefits committee. I witnessed her comittment that all stakeholders had what they needed to make the best decisions for the business. Heather took the time to ensure she understood and prepared for differing stakeholder priorities. Without creativity or innovative ways of thinking, she could not have been effective.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LSTART_IMPACT','Public speaking - sharing experiences and navigated challenges to increase professional visibility; possibly through SHRM, ASEC');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LSTOP_IMPACT','If resources allow, less time on tactical administrative work - Heather is strategic, and an asset to any organization using that skills base');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LCONT_IMPACT','Servant leadership - grooming her team for growth and high competency');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('1d383b44-e8f3-4aa6-afd5-95500d3989be','b9264edb-3da1-4b5c-b9df-38136aaf057f','LDESCRIBE','Rare - It is difficult to find someone in HR who grasps C-Suite business acumen, labor/employment, compliance and day to day employee relations. Heather is among the sharpest people with whom I have ever worked. Her grasp of financials was so refreshing.');
