INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LSTART_TRUST','While he is incredibly authentic, I believe he could benefit from more frequent communication.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LSTOP_INIT','He could stop overthinking the perspectives of others including his superiors. He''s got what it takes.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LCONT_PROD','Transparency is an obvious goal of his - continue that.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LSTOP_COMM','He is a very clear and effective communicator, but sometimes I think he could communicate more frequently.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LCREATIVE','I think he is definitely not worried about maintaining the status quo - he wants to continue to better the processes for NM Vistas and other accountability measures.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LSTART_IMPACT','Start asking deeper questions of others.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LSTOP_IMPACT','You won''t make everyone happy - don''t try to - simply do what is right.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LCONT_IMPACT','Continue being motivated to better the systems in place.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','17677056-94f4-49a4-a4d1-2841c51a99c5','LDESCRIBE','He is thoughtful, intelligent, takes time to formulate wise responses to difficult questions - motivated to get it right.');
