INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LINSPIRE',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LRELAT',3);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','D1',9);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LSTART_TRUST','David is a trustworthy person, and I think his colleagues and team members see this. I also think he''s already doing many things that build trust. I wonder if responsiveness may be a way for him to continue to build trust. There are organizational challenges within PED can complicate this, but the more consistency a leader can provide in replying to communications in a timely manner (even to say "I will be able to review this more closely on DATE") the more team members will trust that leader. David is pulled in a lot of different directions and often in unanticipated ways and times, so this ask is not a small one.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LSTOP_INIT','David could work on stopping the practice of functioning by past precedence in terms of having to respond to issues as they arise. He''s working on this (a great example is thinking about reporting and data availability timelines), but some of the stopping includes starting to advocate strongly for what REA needs in order to do their job well and in a timely manner and working out solutions with other teams to fulfill agency and office goals and priorities.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LCONT_PROD','David should continue to explore ways in which he can build connections with other teams in the agency and identify ways to streamline work.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LSTOP_COMM','I am not certain if this is the case because I do often not see direct communications between David and his team members, but if it is the case that other leadership are communicating directly with REA, I would encourage David to stop that practice and to be the voice of leadership for the team so that he can convey context and rationale, and communicate directly about asks and expectations for team members.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LCREATIVE','David did a great job leading efforts to respond to data availability challenges with an innovative solution that received support from the field and was something he and his colleagues could implement.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LSTART_IMPACT','I would encourage David to start taking time to engage in long-term strategic planning for his team. Sitting down once a year to identify key deliverables, data and other timelines, prerequisite activities, decisions, and other deliverables, and other priorities can be really helpful because it helps illuminate where there may be pain points in the work that can be mitigated with advance planning and it can identify where cross-agency partnerships may enhance work.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LSTOP_IMPACT','David, in his careful consideration of others, often apologizes for asking people to take time to support his work. It''s great to acknowledge someone''s support and show appreciation, but there''s no need to apologize. He''s a leader; we work with and for him; he has the right to ask for our support and engagement.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LCONT_IMPACT','I see David investing in his leadership skills broadly, being increasingly decisive, and communicating his rationale for decisions. He is respectful of his colleagues and is a very good communicator. Keep those things up!');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','cef846d7-2c07-492e-b667-280afa09f694','LDESCRIBE','David is a strong-but-quiet leader who is very conscientious and thoughtful. You can trust him to listen carefully and to respectfully interact with those around him.');
INSERT INTO diagnostic_raters (id,diagnostic_id,name,email,relationship,is_self,completed_at,created_at) VALUES ('b98bce28-abdc-4511-9b31-7061c48a0e61','7ff06448-d55c-450a-ac62-b4f024a45b7f','Brigette Russell','brigette.russell2@ped.nm.gov','Peer',false,'2025-04-26T00:00:00Z','2025-04-26T00:00:00Z');
