INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LRELAT',5);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','D1',10);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LSTART_TRUST','Because I''m director of a different bureau, I can''t really answer this about David''s team, but I can say that in all my interactions with him, he appears to be far more forthright, transparent, and thoughtful than most of the managers within this agency. When he tells me something, I know I''m getting a straight answer and not bureacracy-speak.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LSTOP_INIT','I rated addressing issues before they escalate lower than the others because  there are some underlying problems with data at the agency, and someone in David''s role should be looking for ways to resolve those. As I''m not an internal member of the team, I''m not sure there is anything he is or isn''t doing that gets in the way of this.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LCONT_PROD','N/A I am not really in a position to judge');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LSTOP_COMM','David is a very effective communicator, which people who work in data aren''t always. This is a real strength for him.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LCREATIVE','He came up with a creative way to get statewide assessment results more quickly by redefining one of the variables underlying it. I was amazed and so impressed when I heard the idea. It is going to make a LOT of people''s work easier, mine included.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LSTART_IMPACT','Being more intentional about building relationships across the agency.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LSTOP_IMPACT','Hesitating to speak up more -- leaders here need to hear his voice.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LCONT_IMPACT','Being calm, courteous and gracious.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b98bce28-abdc-4511-9b31-7061c48a0e61','LDESCRIBE','Intelligent, thoughtful, courteous, collaborative, innovative, calm, kind.');
