INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LSTART_TRUST','N/A');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LSTOP_INIT','David is proactive in planning the team''s work and needs.  He allows a high degree of autonomy in our work already.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LCONT_PROD','Planning work in advance, maintaining our systems of tracking tasks so that there is visibility of team member capacity.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LSTOP_COMM','Communication within the team is consistent');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LCREATIVE','David directs the team with a lot of flexibility.  I think his general approach to gray areas in our work processes or new responsibilities assigned to our team leads to: 1.) smoother day-to-day work, 2.) more engagement and satisfaction from stakeholders when they can give feedback, in our case mostly school leaders, and 3.) gradual improvement of systems rather than carrying redundant or inefficient methods.  
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LSTART_IMPACT','Maintaining consistent expectations of work and transparency in workload/capacity across the team and our partners.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LSTOP_IMPACT','N/A');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LCONT_IMPACT','Identifying recurring tasks or operations that can be done more efficiently. His facilitation of communication is also very good: weekly 1 on 1 meetings with David, weekly team meetings, and additional check-ins as needed.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','d4ddef9c-840f-4978-801e-d07cac6cfbf1','LDESCRIBE','Diplomatic, proactive, diligent');
