INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','D1',9);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LSTART_TRUST','I cannot think of anything additional to add, as David consistently demonstrates honesty and transparency with colleagues. He openly communicates important information, including any errors that have occurred. He also provides clear and accurate guidance about what the team can and cannot do, ensuring everyone has a shared understanding of expectations and limitations.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LSTOP_INIT','None');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LCONT_PROD','David is a dedicated and hardworking leader who consistently demonstrates trust in his colleagues’ work. He shows genuine compassion toward his subordinates, fostering a supportive and respectful work environment. In my opinion, these qualities are key reasons why REA data analysts appreciate working under his leadership.
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LSTOP_COMM','None');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LCREATIVE','I am being biased on my answer, but the automated briefing packet is one of the best innovations that David took the lead.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LSTART_IMPACT','I am not fully certain about David’s skills in handling difficult conversations and holding others accountable. However, these are areas I would strongly encourage him to continue developing, especially as he advances in his career as a manager. Strengthening these skills will help him navigate challenging situations effectively and lead his team with clarity and confidence.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LSTOP_IMPACT','None');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LCONT_IMPACT','Communication, honesty and hard work');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','8f677890-6fa7-45b5-8421-a925e80c344d','LDESCRIBE','Teammate, team player, trusted ally.
