INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','D1',7);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LSTART_TRUST','Trust has also been impacted by broader leadership transitions and organizational dynamics, though this is not solely attributable to the individual in this role. Increasing consistent, timely, and proactive communication—such as regular check-ins, clear and transparent explanations of decision-making, and structured opportunities for staff voice and agency could help rebuild confidence and strengthen relationships across the team.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LSTOP_INIT','Given that I do not directly report to this individual or work closely with the team at that level, it is difficult to identify a specific behavior that should stop. From my limited vantage point, however, one potential area to reflect on is whether decision-making processes may at times feel centralized. If so, creating additional space for distributed leadership and clarifying decision-making authority could further empower team members to take initiative with confidence.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LCONT_PROD','Given my limited direct engagement at the team level, I would encourage this leader to continue providing clear direction and maintaining a steady focus on priorities. Consistent expectations and alignment around goals appear to support productivity and help ensure the team remains focused on key outcomes.
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LSTOP_COMM','Since I don’t work directly under this leader or interact closely with their team, it’s difficult to identify something specific they should stop. From my perspective, one area to consider might be reducing reliance on indirect or delayed communication—ensuring messages are timely and clear could help strengthen overall effectiveness and support staff in taking action with confidence.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LCREATIVE','One particularly valuable approach this leader has introduced is improving data transparency within the hierarchy. By cleaning up and organizing the information, it’s much easier for teams to understand and act on it. Moving forward, presenting this data in more accessible, “human-friendly” terms could make it even more useful and actionable for everyone.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LSTART_IMPACT','One way this leader could elevate their impact is by increasing direct, visible engagement with teams—checking in more regularly and creating structured opportunities for open dialogue. This could help strengthen relationships, build trust, and ensure staff feel heard and empowered to take initiative.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LSTOP_IMPACT','Given my limited direct interaction with the team, it’s hard to pinpoint specific behaviors to stop. From my perspective, reducing reliance on highly formal or indirect communication could help—shifting toward more straightforward, timely, and approachable messaging may enhance clarity and effectiveness.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LCONT_IMPACT','This leader excels at providing clear direction and maintaining focus on priorities. Continuing to set clear expectations and communicate goals helps teams stay aligned, productive, and confident in their work.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','613a99f2-6088-4e3d-b1f7-1c5fe3030d75','LDESCRIBE','Purposeful');
