INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b8e94a18-d521-4b25-be93-a9f1d83ea145','LACCT',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','b8e94a18-d521-4b25-be93-a9f1d83ea145','LEXPECT',5);
