INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LSTART_TRUST','One thing that could further strengthen trust is increasing transparency around decision-making and priorities. Providing a bit more context behind strategic choices would help the team feel even more aligned and included. Overall, the foundation of trust is already strong, and this would elevate it further.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LSTOP_INIT','Creating more room for ownership would help build confidence and empowerment.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LCONT_PROD','Continuing to provide clear direction and support has a strong positive impact on team productivity. Your accessibility and guidance help the team stay aligned, focused, and confident in moving work forward.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LSTOP_COMM','At this time, I do not see any consistent behaviors that need to stop. Communication and leadership effectiveness are strong, and the current approach is working well for the team.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LCREATIVE','A particularly valuable approach has been creating space for open dialogue and collaborative problem-solving. Encouraging team input before making decisions has strengthened engagement, alignment, and overall effectiveness.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LSTART_IMPACT','One thing that could further elevate your leadership impact is sharing more of your long-term vision and strategic thinking with the team. Providing greater insight into future goals and priorities would help strengthen alignment, ownership, and overall engagement.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LSTOP_IMPACT','One opportunity for increased effectiveness may be stepping back slightly in situations where the team can independently navigate solutions. Allowing more space for ownership could further strengthen confidence, accountability, and overall team growth.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LCONT_IMPACT','One thing you do exceptionally well is being responsive and accessible. Your timely communication and willingness to support the team create clarity, reduce bottlenecks, and help us stay productive and aligned.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','5d2f3114-e1f2-4514-bce8-40d21fea8d70','LDESCRIBE','Approachable, responsive, supportive, decisive, and empowering. David fosters collaboration, provides clear guidance, and builds trust while encouraging the team to take initiative.');
INSERT INTO diagnostic_raters (id,diagnostic_id,name,email,relationship,is_self,completed_at,created_at) VALUES ('3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','7ff06448-d55c-450a-ac62-b4f024a45b7f','Happy Miller','happy.miller@rrps.net','External Partner',false,'2025-04-26T00:00:00Z','2025-04-26T00:00:00Z');
