INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LSTRAT',3);
