INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LINSPIRE',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LRELAT',4);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,score) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','D1',9);
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LSTART_TRUST','It''s not so much "start" as "increase". Communication and transparency about business rules and processes helps districts understand and interpret the data correctly. I understand that it is a challenge to communicate with such a wide array of internal and external stakeholders and that David often does not have the authority to set timelines, etc., but greater communication and transparency would help build trust.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LSTOP_INIT','This is a hard question to answer as I am not internal to PED. I wish that AREA leadership had greater authority to make decisions and carry them out but high level decisions are made by PED Cabinet members. The PED Accountability team is also required to seek approval from the U.S. Department of Education for many issues related to school accountability. So there is a limited range within which they can take initiative. However, it feels like within this context the Accountability team is not as proactive as they could be.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LCONT_PROD','David has been willing to meaningfully engage with some district stakeholders to develop processes that work for both PED and the districts. We greatly appreciate his willingness to listen and take action based on district feedback.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LSTOP_COMM','This is challenging when dealing with a wide variety of stakeholders and time pressures, but David sometimes responds quickly to emails and sometimes we don''t receive a response at all. It would be nice to always receive a response even if the response is an explanation of why the question cannot be answered.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LCREATIVE','This shouldn''t really be considered to be creative or innovative, but I credit David and his team (including advisors from the Center for Assessment) with documenting practices and business rules. For a while there was so much turnover that each year there were new interpretations of the state ESSA plan and its associated business rules. I credit David with bringing some longitudinal stability to the process.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LSTART_IMPACT','Again, it''s not "start" but "increase" or "improve". 
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LSTOP_IMPACT','I am not aware of anything that should be stopped.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LCONT_IMPACT','I appreciate that David listens to feedback and cares about the details.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','3e49e7eb-6840-4ec1-bde7-7dd0a56a2498','LDESCRIBE','Calm, considerate, thoughtful');
