INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LSTART_TRUST','Have confidence; he succeeds where many others before him have failed.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LSTOP_INIT','Try to stay focused on core-job responsibilities to produce data.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LCONT_PROD','Building out core data-infrastructure.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LSTOP_COMM','Providing clearer expectations and more advance notice would help the team plan more effectively, reduce unnecessary stress, and improve overall productivity. More proactive communication would strengthen trust and allow everyone to perform at a higher level.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LCREATIVE','One particularly valuable innovation this leader introduced was creating structured opportunities for cross-team collaboration');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LSTART_IMPACT','One thing this leader could start doing to elevate their impact is communicating a clearer long-term vision and connecting daily work to broader strategic goals');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LSTOP_IMPACT','One thing this leader could stop doing to become more effective is taking on too many responsibilities personally.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LCONT_IMPACT','One thing this leader does exceptionally well and should absolutely continue doing is fostering a culture of openness and approachability.');
INSERT INTO diagnostic_responses (diagnostic_id,rater_id,question_code,text_response) VALUES ('7ff06448-d55c-450a-ac62-b4f024a45b7f','228851a5-d457-4e1d-858b-afc282f51e1f','LDESCRIBE','I would describe this leader as strategic, thoughtful, and mission-driven');
